def pca_inverse(coeffs, pca_type='pred'):
    """PCA反压缩: 系数 → 900维三轴波形"""
    if pca_type == 'pred':
        mean = np.array(PCA_MEAN_900, dtype=np.float32)
        matrix = np.array(PCA_MATRIX_900, dtype=np.float32)
        n_coeffs = PCA_OUT_PRED
    else:
        mean = np.array(PCA_MEAN_300, dtype=np.float32)
        matrix = np.array(PCA_MATRIX_300, dtype=np.float32)
        n_coeffs = PCA_OUT_HIST

    pca_float = np.array(coeffs[:n_coeffs], dtype=np.float32) * QUANT_SCALE
    recon = pca_float @ matrix + mean
    waveform = np.zeros((3, 300), dtype=np.float32)
    waveform[0] = recon[0:300]
    waveform[1] = recon[300:600]
    waveform[2] = recon[600:900]
    return waveform